import { useEffect, useState } from "react";
import {
  addDoc,
  collection,
  onSnapshot,
  orderBy,
  query,
  serverTimestamp,
} from "firebase/firestore";
import { db } from "../firebase";
import { useAuth } from "../context/AuthContext";

const fallbackActionTypes = [
  { id: "clearance", label: "Clearance", value: "Clearance" },
  { id: "refund", label: "Refund", value: "Refund" },
  { id: "bells", label: "Bells", value: "Bells" },
];

export default function ActionSelector() {
  const { currentUser, userProfile } = useAuth();
  const [actionTypes, setActionTypes] = useState(fallbackActionTypes);
  const [message, setMessage] = useState("");
  const [logging, setLogging] = useState(false);

  useEffect(() => {
    const actionTypesQuery = query(collection(db, "action_types"), orderBy("name", "asc"));

    const unsubscribe = onSnapshot(
      actionTypesQuery,
      (snapshot) => {
        const liveActionTypes = snapshot.docs.map((actionTypeDoc) => {
          const data = actionTypeDoc.data();
          const name = data.name || data.label || actionTypeDoc.id;
          return { id: actionTypeDoc.id, label: name, value: name };
        });

        if (liveActionTypes.length > 0) {
          setActionTypes(liveActionTypes);
        }
      },
      () => {
        // Keep fallback types if query fails (e.g. missing index)
      }
    );

    return unsubscribe;
  }, []);

  const handleLogAction = async (actionType) => {
    if (!currentUser || logging) return;

    setLogging(true);
    try {
      const agentName =
        userProfile?.name || currentUser.displayName || currentUser.email || "Unknown Agent";

      await addDoc(collection(db, "agent_actions"), {
        agentId: currentUser.uid,
        agentName,
        actionType,
        timestamp: serverTimestamp(),
      });

      setMessage(`Logged: ${actionType}`);
      window.setTimeout(() => setMessage(""), 2200);
    } catch (err) {
      console.error("Failed to log action:", err);
      setMessage("Failed to log action");
      window.setTimeout(() => setMessage(""), 2200);
    } finally {
      setLogging(false);
    }
  };

  return (
    <section className="card p-6 mb-8">
      <div className="flex items-center justify-between gap-4 mb-4">
        <div>
          <h2 className="card-header">Quick Actions</h2>
          <p className="card-subtext">Log the action you are taking on this call.</p>
        </div>
        {message && (
          <span className="text-sm font-bold text-green-700 bg-green-50 border border-green-100 px-3 py-1.5 rounded-full">
            {message}
          </span>
        )}
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
        {actionTypes.map((actionType) => (
          <button
            key={actionType.id}
            type="button"
            disabled={logging}
            onClick={() => handleLogAction(actionType.value)}
            className="min-h-[82px] rounded-input border border-brand-border bg-brand-bg
                       hover:bg-white hover:border-[#bfd7f6] hover:shadow-sm
                       transition-all text-left p-4 disabled:opacity-50"
          >
            <span className="block text-base font-extrabold text-brand-navy">{actionType.label}</span>
            <span className="block text-xs font-semibold text-brand-slate mt-1">Log action</span>
          </button>
        ))}
      </div>
    </section>
  );
}
